mapper.sql:
n.status = 'ACTIVE' and (n.visibility = 'PUBLIC'
or n.author_member_id = #{viewerMemberId} or (n.visibility = 'FRIENDS' and exists ( select 1 from friendships f where f.status = 'ACCEPTED' and ((f.requester_member_id = #{viewerMemberId} and f.addressee_member_id = n.author_member_id) or (f.requester_member_id = n.author_member_id and f.addressee_member_id = #{viewerMemberId}))))
)
